3_real_world_example.code:
fetch('/api/unreliable-endpoint')
  .then(res => {
    if (!res.ok) throw new Error('Server returned 500');
    return res.json();
  })
  .then(data => console.log('Data:', data))
  .catch(err => {
    console.warn('Network failed, using fallback data.', err.message);
    // Recovery: returning a normal value turns the chain back to 'fulfilled'
    return { id: 0, name: 'Offline User' }; 
  })
  .then(fallbackData => {
    console.log('UI updated with:', fallbackData);
  });

